import React, { useContext, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Container } from 'react-bootstrap'; 
// Importaciones de Contextos
import { SettingsContext } from '../context/SettingsContext'; 
// Componentes
import SearchBox from './SearchBox'; 
import HeaderSkeleton from './HeaderSkeleton'; 
import styles from './Header.module.css'; 

const Header = () => {
  const navigate = useNavigate();
  // Se mantienen las variables de contexto por si se usan en el futuro
  const { settings, loading: settingsLoading } = useContext(SettingsContext);
  
  useEffect(() => {
    if (settings?.accentColor) {
      document.documentElement.style.setProperty('--cta-color', settings.accentColor);
    }
  }, [settings]);

  const isLoading = settingsLoading;

  if (isLoading) {
     return <HeaderSkeleton />;
  }
  
  // Usamos un nombre simple para evitar conflictos de acento
  const siteName = (settings?.siteName || 'TECNOTITLÁN').toUpperCase(); 
  
  return (
    <header 
      className={`w-full sticky top-0 z-50 transition-all duration-300 shadow-md ${styles.header}`}
    >
      <Container> 
        {/* CRÍTICO: d-flex y justify-content-between para alinear Logo, Search y Acciones */}
        <div className="d-flex justify-content-between align-items-center h-full"> 
          
          {/* 1. Logo / Nombre del Sitio (Izquierda) */}
          <Link 
            to="/" 
            className={`${styles.logoText} d-flex align-items-center gap-2 flex-shrink-0`} 
          > 
            <div className="flex flex-col items-start">
                <span>
                  {siteName}
                </span>
                <span>
                  Tecnología con Raíces
                </span>
            </div>
          </Link>

          {/* 2. Barra de búsqueda (Centrada, solo Desktop) */}
          {/* w-1/2 max-w-lg mx-auto para centrar y ocupar el espacio restante */}
          <div className="d-none d-lg-block w-1/2 max-w-lg mx-auto px-5">
            <SearchBox /> 
          </div>
          
          {/* 3. Navegación Derecha (Mockup de espacio) */}
          {/* Usamos un div con un ancho similar al logo para forzar la simetría */}
          <div className="d-flex align-items-center gap-4 w-40 flex-shrink-0 justify-content-end">
             {/* Aquí irán los botones de Carrito y Usuario */}
          </div>

        </div>
        
        {/* Barra de búsqueda (Solo Móvil - Se extiende en su propia fila) */}
        <div className="d-lg-none mt-3">
          <SearchBox />
        </div>
      </Container>
    </header>
  );
};

export default Header;
